def deleteDuplicates(head):
    cur = head
    while cur and cur.next:
        if cur.val == cur.next.val:
            cur.next = cur.next.next
        else:
            cur = cur.next
    return head

def mergeTwoLists(l1, l2):
    dummy = ListNode(0)
    cur = dummy
    while l1 and l2:
        if l1.val <= l2.val:
            cur.next, l1 = l1, l1.next
        else:
            cur.next, l2 = l2, l2.next
        cur = cur.next
    cur.next = l1 or l2
    return dummy.next

def hasCycle(head):
    slow = fast = head
    while fast and fast.next:
        slow = slow.next
        fast = fast.next.next
        if slow is fast:
            return True
    return False

def removeNthFromEnd(head, n):
    dummy = ListNode(0, head)
    slow = fast = dummy
    for _ in range(n):
        fast = fast.next
    while fast.next:
        slow = slow.next
        fast = fast.next
    slow.next = slow.next.next
    return dummy.next

def isValid(s):
    stack, pairs = [], {')':'(', ']':'[', '}':'{'}
    for ch in s:
        if ch in '([{':
            stack.append(ch)
        else:
            if not stack or stack.pop() != pairs[ch]:
                return False
    return not stack

class MyQueue:
    def __init__(self):
        self.in_st, self.out_st = [], []
    def push(self, x):
        self.in_st.append(x)
    def pop(self):
        self._move()
        return self.out_st.pop()
    def peek(self):
        self._move()
        return self.out_st[-1]
    def empty(self):
        return not self.in_st and not self.out_st
    def _move(self):
        if not self.out_st:
            while self.in_st:
                self.out_st.append(self.in_st.pop())

class MinStack:
    def __init__(self):
        self.st, self.min_st = [], []
    def push(self, x):
        self.st.append(x)
        self.min_st.append(x if not self.min_st else min(x, self.min_st[-1]))
    def pop(self):
        self.st.pop(); self.min_st.pop()
    def top(self):
        return self.st[-1]
    def getMin(self):
        return self.min_st[-1]

def evalRPN(tokens):
    st, ops = [], {'+','-','*','/'}
    for t in tokens:
        if t in ops:
            b, a = st.pop(), st.pop()
            if t == '+': st.append(a + b)
            elif t == '-': st.append(a - b)
            elif t == '*': st.append(a * b)
            else: st.append(int(a / b))
        else:
            st.append(int(t))
    return st[0]

def maxSlidingWindow(nums, k):
    from collections import deque
    q, res = deque(), []
    for i, v in enumerate(nums):
        while q and nums[q[-1]] < v:
            q.pop()
        q.append(i)
        if q[0] <= i - k:
            q.popleft()
        if i >= k - 1:
            res.append(nums[q[0]])
    return res

def inorderTraversal(root):
    res, st = [], []
    cur = root
    while cur or st:
        while cur:
            st.append(cur); cur = cur.left
        cur = st.pop()
        res.append(cur.val)
        cur = cur.right
    return res

def levelOrder(root):
    if not root: return []
    res, q = [], [root]
    while q:
        vals, nq = [], []
        for node in q:
            vals.append(node.val)
            if node.left: nq.append(node.left)
            if node.right: nq.append(node.right)
        res.append(vals); q = nq
    return res

def maxDepth(root):
    if not root: return 0
    return 1 + max(maxDepth(root.left), maxDepth(root.right))

def isSymmetric(root):
    def check(a, b):
        if not a and not b: return True
        if not a or not b: return False
        return a.val == b.val and check(a.left, b.right) and check(a.right, b.left)
    return check(root, root)

def isValidBST(root):
    def dfs(n, lo, hi):
        if not n: return True
        if not (lo < n.val < hi): return False
        return dfs(n.left, lo, n.val) and dfs(n.right, n.val, hi)
    return dfs(root, float('-inf'), float('inf'))

def kthSmallest(root, k):
    st, cur = [], root
    while cur or st:
        while cur:
            st.append(cur); cur = cur.left
        cur = st.pop()
        k -= 1
        if k == 0: return cur.val
        cur = cur.right

def numIslands(grid):
    if not grid: return 0
    m, n, cnt = len(grid), len(grid[0]), 0
    def dfs(i, j):
        if 0 <= i < m and 0 <= j < n and grid[i][j] == '1':
            grid[i][j] = '0'
            for x, y in ((i-1,j),(i+1,j),(i,j-1),(i,j+1)):
                dfs(x, y)
    for i in range(m):
        for j in range(n):
            if grid[i][j] == '1':
                cnt += 1; dfs(i, j)
    return cnt

def canFinish(numCourses, prerequisites):
    g = [[] for _ in range(numCourses)]
    indeg = [0] * numCourses
    for a, b in prerequisites:
        g[b].append(a); indeg[a] += 1
    q = [i for i, d in enumerate(indeg) if d == 0]
    taken = 0
    while q:
        nq = []
        for u in q:
            taken += 1
            for v in g[u]:
                indeg[v] -= 1
                if indeg[v] == 0: nq.append(v)
        q = nq
    return taken == numCourses

def dijkstra(n, edges, src):
    import heapq
    g = [[] for _ in range(n)]
    for u, v, w in edges:
        g[u].append((v, w))
    dist = [float('inf')] * n; dist[src] = 0
    pq = [(0, src)]
    while pq:
        d, u = heapq.heappop(pq)
        if d > dist[u]: continue
        for v, w in g[u]:
            nd = d + w
            if nd < dist[v]:
                dist[v] = nd; heapq.heappush(pq, (nd, v))
    return dist

def merge_sort(a):
    if len(a) <= 1: return a
    mid = len(a) // 2
    return merge(merge_sort(a[:mid]), merge_sort(a[mid:]))

def merge(l, r):
    res, i, j = [], 0, 0
    while i < len(l) and j < len(r):
        if l[i] <= r[j]: res.append(l[i]); i += 1
        else: res.append(r[j]); j += 1
    return res + l[i:] + r[j:]

def heap_sort(a):
    n = len(a)
    for i in range(n // 2 - 1, -1, -1):
        _sift(a, i, n)
    for end in range(n - 1, 0, -1):
        a[0], a[end] = a[end], a[0]; _sift(a, 0, end)
    return a

def _sift(a, i, n):
    while True:
        l, r = 2 * i + 1, 2 * i + 2
        m = i
        if l < n and a[l] > a[m]: m = l
        if r < n and a[r] > a[m]: m = r
        if m == i: break
        a[i], a[m] = a[m], a[i]; i = m

def search(nums, target):
    lo, hi = 0, len(nums) - 1
    while lo <= hi:
        mid = (lo + hi) // 2
        if nums[mid] == target: return mid
        if nums[lo] <= nums[mid]:
            if nums[lo] <= target < nums[mid]: hi = mid - 1
            else: lo = mid + 1
        else:
            if nums[mid] < target <= nums[hi]: lo = mid + 1
            else: hi = mid - 1
    return -1

def two_sum(nums, target):
    seen = {}
    for i, v in enumerate(nums):
        if target - v in seen:
            return [seen[target - v], i]
        seen[v] = i
    return []

def lengthOfLongestSubstring(s):
    last, lo, ans = {}, 0, 0
    for i, ch in enumerate(s):
        if ch in last and last[ch] >= lo:
            lo = last[ch] + 1
        last[ch] = i
        ans = max(ans, i - lo + 1)
    return ans

def fib(n):
    if n < 2: return n
    a, b = 0, 1
    for _ in range(n - 1):
        a, b = b, a + b
    return b

def hanoi(n, A='A', B='B', C='C'):
    if n == 0: return []
    return hanoi(n - 1, A, C, B) + [f'{A}->{C}'] + hanoi(n - 1, B, A, C)

def climbStairs(n):
    if n <= 2: return n
    a, b = 1, 2
    for _ in range(3, n + 1):
        a, b = b, a + b
    return b

def lengthOfLIS(nums):
    import bisect
    tails = []
    for v in nums:
        i = bisect.bisect_left(tails, v)
        if i == len(tails): tails.append(v)
        else: tails[i] = v
    return len(tails)

def knapsack01(W, w, v):
    dp = [0] * (W + 1)
    for i in range(len(w)):
        for j in range(W, w[i] - 1, -1):
            dp[j] = max(dp[j], dp[j - w[i]] + v[i])
    return dp[W]

def longestCommonSubsequence(text1, text2):
    m, n = len(text1), len(text2)
    dp = [[0] * (n + 1) for _ in range(m + 1)]
    for i in range(m):
        for j in range(n):
            if text1[i] == text2[j]:
                dp[i+1][j+1] = dp[i][j] + 1
            else:
                dp[i+1][j+1] = max(dp[i][j+1], dp[i+1][j])
    return dp[m][n]
